@pytest.mark.asyncio
async def test_error_response_auth_401() -> None:
    """401 Unauthorized when creating a response with invalid API key."""
    client = create_client(
        api_key="test-key",
        base_url=os.environ["MOCK_SERVER_URL"] + "/fixtures/error_response_auth_401",
    )
    request = CreateResponseRequest.from_json('{"input":"Hello","model":"gpt-4o"}')

    with pytest.raises(Exception) as exc_info:  # noqa: B017
        await client.create_response(request)
    assert "Authentication" in type(exc_info.value).__name__  # noqa: S101


